import React, { useState, useEffect, useRef } from 'react';
import { Menu, X, Sparkles, Sun, Moon, User as UserIcon, LogOut, Settings, Map } from 'lucide-react';
import { ViewType, User } from '../App';

interface NavbarProps {
  isDark: boolean;
  toggleTheme: () => void;
  navigateTo: (view: ViewType) => void;
  currentView: ViewType;
  user: User | null;
  onLogout: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ isDark, toggleTheme, navigateTo, currentView, user, onLogout }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [profileMenuOpen, setProfileMenuOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setProfileMenuOpen(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const navLinks: { name: string; view: ViewType }[] = [
    { name: 'How it Works', view: 'how-it-works' },
    { name: 'Features', view: 'features' },
    { name: 'Blog', view: 'blog' },
  ];

  const handleAction = (view: ViewType) => {
    navigateTo(view);
    setMobileMenuOpen(false);
    setProfileMenuOpen(false);
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      isScrolled 
        ? 'glass-morphism py-3 shadow-sm' 
        : 'bg-transparent py-5'
    }`}>
      <div className="container mx-auto px-4 md:px-6">
        <div className="flex items-center justify-between">
          <button 
            onClick={() => handleAction('home')} 
            className="flex items-center gap-2 cursor-pointer group outline-none"
          >
            <div className="bg-amber-500 p-2 rounded-lg group-hover:scale-110 transition-transform">
              <Sparkles className="text-dark w-5 h-5" />
            </div>
            <span className="text-xl font-black tracking-tight text-dark dark:text-white">
              YourTripy
            </span>
          </button>

          <div className="hidden md:flex items-center gap-8">
            {navLinks.map((link) => (
              <button 
                key={link.name}
                onClick={() => handleAction(link.view)}
                className={`text-sm font-bold transition-colors outline-none ${
                  currentView === link.view 
                    ? 'text-amber-600 dark:text-amber-400' 
                    : 'text-slate-600 dark:text-slate-400 hover:text-amber-600 dark:hover:text-amber-400'
                }`}
              >
                {link.name}
              </button>
            ))}
          </div>

          <div className="hidden md:flex items-center gap-3">
            <button 
              onClick={toggleTheme}
              className="p-2 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg transition-all outline-none"
              aria-label="Toggle Theme"
            >
              {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            <div className="w-px h-5 bg-slate-200 dark:bg-slate-800 mx-2" />

            {user ? (
              <div className="relative" ref={profileRef}>
                <button 
                  onClick={() => setProfileMenuOpen(!profileMenuOpen)}
                  className="flex items-center gap-2 p-1.5 pl-3 pr-4 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-all outline-none border border-transparent hover:border-amber-500/30"
                >
                  <span className="text-sm font-bold text-slate-700 dark:text-slate-300">{user.name.split(' ')[0]}</span>
                  {user.avatar ? (
                    <img src={user.avatar} className="w-7 h-7 rounded-full object-cover" alt="Profile" />
                  ) : (
                    <div className="w-7 h-7 bg-amber-500 rounded-full flex items-center justify-center text-dark">
                      <UserIcon className="w-4 h-4" />
                    </div>
                  )}
                </button>

                {profileMenuOpen && (
                  <div className="absolute right-0 mt-3 w-56 glass-morphism border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl py-2 animate-in fade-in zoom-in-95 duration-200">
                    <div className="px-4 py-3 border-b border-slate-100 dark:border-slate-800">
                      <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Signed in as</p>
                      <p className="text-sm font-bold text-slate-900 dark:text-white truncate">{user.email}</p>
                    </div>
                    <div className="py-1">
                      <button onClick={() => handleAction('planner')} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-bold text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 text-left transition-colors">
                        <Map className="w-4 h-4 text-amber-500" /> My Trips
                      </button>
                      <button onClick={() => alert("Settings coming soon")} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-bold text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 text-left transition-colors">
                        <Settings className="w-4 h-4 text-slate-400" /> Settings
                      </button>
                    </div>
                    <div className="pt-1 mt-1 border-t border-slate-100 dark:border-slate-800">
                      <button 
                        onClick={() => { onLogout(); setProfileMenuOpen(false); }} 
                        className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-bold text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 text-left transition-colors"
                      >
                        <LogOut className="w-4 h-4" /> Log Out
                      </button>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <div className="flex items-center gap-2">
                <button 
                  onClick={() => handleAction('login')} 
                  className="px-4 py-2 text-sm font-bold text-slate-700 dark:text-slate-300 hover:text-amber-600 dark:hover:text-amber-400 transition-colors outline-none"
                >
                  Log In
                </button>
                <button 
                  onClick={() => handleAction('signup')}
                  className="px-5 py-2.5 bg-dark dark:bg-white text-white dark:text-dark text-sm font-bold rounded-xl shadow-lg hover:opacity-90 transition-all active:scale-95 outline-none"
                >
                  Get Started
                </button>
              </div>
            )}
          </div>

          <div className="flex md:hidden items-center gap-2">
            <button onClick={toggleTheme} className="p-2 text-slate-600 dark:text-slate-400 outline-none">
              {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <button className="p-2 text-slate-600 dark:text-slate-400 outline-none" onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
              {mobileMenuOpen ? <X /> : <Menu />}
            </button>
          </div>
        </div>
      </div>

      {mobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 right-0 glass-morphism border-t border-slate-200 dark:border-slate-800 p-6 flex flex-col gap-4 shadow-2xl animate-in slide-in-from-top-2">
          {user && (
            <div className="flex items-center gap-4 p-4 bg-slate-50 dark:bg-slate-900 rounded-2xl mb-2">
               <div className="w-10 h-10 bg-amber-500 rounded-full flex items-center justify-center shrink-0 text-dark">
                  <UserIcon className="w-5 h-5" />
               </div>
               <div className="overflow-hidden">
                  <p className="font-bold text-slate-900 dark:text-white truncate">{user.name}</p>
                  <p className="text-xs text-slate-500 truncate">{user.email}</p>
               </div>
            </div>
          )}
          {navLinks.map((link) => (
            <button key={link.name} onClick={() => handleAction(link.view)} className="text-lg font-bold text-left text-slate-900 dark:text-white">{link.name}</button>
          ))}
          <div className="h-px bg-slate-200 dark:bg-slate-800 my-2" />
          {user ? (
            <button onClick={onLogout} className="w-full py-3 text-center font-bold text-red-500 bg-red-50 dark:bg-red-900/10 rounded-xl">Log Out</button>
          ) : (
            <>
              <button onClick={() => handleAction('login')} className="w-full py-3 text-center font-bold text-slate-700 dark:text-slate-300 rounded-xl border border-slate-200 dark:border-slate-800">Log In</button>
              <button onClick={() => handleAction('signup')} className="w-full py-3 text-center font-bold text-white bg-dark dark:bg-white dark:text-dark rounded-xl block">Get Started</button>
            </>
          )}
        </div>
      )}
    </nav>
  );
};

