import React, { useState, useEffect } from 'react';
import { 
  GripVertical, Plus, Trash2, MapPin, Navigation, 
  MoreHorizontal, Calendar, Loader2, 
  Sparkles, RefreshCcw, Send, ArrowLeft, Clock
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { ViewType } from '../App';

interface Activity {
  id: string;
  time: string;
  title: string;
  category: string;
  duration: string;
}

interface PlannerPageProps {
  initialQuery?: string;
  navigateTo: (view: ViewType) => void;
}

const PlannerPage: React.FC<PlannerPageProps> = ({ initialQuery, navigateTo }) => {
  const [activeDay, setActiveDay] = useState(1);
  const [itinerary, setItinerary] = useState<Activity[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [query, setQuery] = useState(initialQuery || '');
  const [destinationName, setDestinationName] = useState(initialQuery || 'New Trip');

  useEffect(() => {
    if (initialQuery) {
      generateAITrip(initialQuery);
    }
  }, []);

  const generateAITrip = async (prompt: string) => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a one-day travel itinerary for: ${prompt}. Return exactly 4 activities in a logical time sequence. JSON format only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                title: { type: Type.STRING },
                category: { type: Type.STRING },
                duration: { type: Type.STRING }
              },
              required: ["time", "title", "category", "duration"]
            }
          }
        },
      });

      const data = JSON.parse(response.text || '[]');
      setItinerary(data.map((item: any) => ({ ...item, id: Math.random().toString(36).substr(2, 9) })));
      setDestinationName(prompt.split('in').pop()?.trim() || prompt.split(' ').slice(0, 2).join(' '));
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("AI Co-pilot encountered an error. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const removeActivity = (id: string) => setItinerary(prev => prev.filter(item => item.id !== id));
  const addActivity = () => {
    setItinerary([...itinerary, { id: Math.random().toString(36).substr(2, 9), time: "08:00 PM", title: "Custom Stop", category: "Custom", duration: "1h" }]);
  };

  return (
    <div className="pt-24 min-h-screen bg-slate-50 dark:bg-dark/95 flex flex-col">
      <div className="bg-white dark:bg-dark border-b border-slate-200 dark:border-slate-800 sticky top-16 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button onClick={() => navigateTo('home')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors outline-none">
            <ArrowLeft className="w-5 h-5 text-slate-500" />
          </button>
          <div className="text-left">
            <h1 className="text-xl font-extrabold text-slate-900 dark:text-white flex items-center gap-2 capitalize">
              <MapPin className="w-5 h-5 text-amber-500" />
              {destinationName}
            </h1>
            <p className="text-xs text-slate-500 font-medium tracking-wide">Interactive Draft</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="relative group flex-grow md:w-80">
            <input 
              type="text" 
              placeholder="Refine your trip..."
              className="w-full pl-5 pr-12 py-3 bg-slate-100 dark:bg-slate-800 border-2 border-transparent focus:bg-white dark:focus:bg-slate-900 focus:border-amber-500 rounded-2xl text-sm transition-all outline-none text-slate-900 dark:text-white font-medium"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && generateAITrip(query)}
            />
            <button onClick={() => generateAITrip(query)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-amber-500 outline-none transition-colors">
              <Send className="w-5 h-5" />
            </button>
          </div>
          <button onClick={() => alert("Trip saved!")} className="px-6 py-3 bg-dark dark:bg-white text-white dark:text-dark text-sm font-black rounded-2xl shadow-lg hover:opacity-90 transition-all outline-none">Save</button>
        </div>
      </div>

      <div className="flex-grow flex flex-col lg:flex-row container mx-auto px-4 py-8 gap-8">
        <aside className="lg:w-1/4 space-y-6">
          <div className="bg-white dark:bg-dark p-8 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm">
            <h4 className="font-black text-slate-900 dark:text-white mb-8 flex items-center justify-between uppercase text-xs tracking-[0.2em] opacity-60">Your Timeline <Calendar className="w-4 h-4" /></h4>
            <div className="space-y-3">
              {[1, 2, 3].map(day => (
                <button 
                  key={day} 
                  onClick={() => setActiveDay(day)}
                  className={`w-full text-left px-5 py-4 rounded-2xl text-sm font-black transition-all flex items-center justify-between outline-none ${
                    activeDay === day ? 'bg-amber-500 text-dark shadow-xl shadow-amber-500/10 scale-105' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'
                  }`}
                >
                  Day {day}
                </button>
              ))}
            </div>
          </div>
          <div className="bg-dark rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-amber-500/10 blur-3xl rounded-full"></div>
            <h4 className="font-black flex items-center gap-3 mb-6 uppercase text-xs tracking-widest text-amber-500"><Sparkles className="w-4 h-4 fill-current" /> AI Co-pilot</h4>
            <div className="space-y-3 relative z-10">
              <button onClick={() => generateAITrip(`Make the day for ${query} more budget friendly`)} className="w-full py-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-xs font-black uppercase tracking-wider transition-all">Budget Friendly</button>
              <button onClick={() => generateAITrip(`Add nature spots to ${query}`)} className="w-full py-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-xs font-black uppercase tracking-wider transition-all">Nature Focus</button>
            </div>
          </div>
        </aside>

        <div className="lg:w-3/4 space-y-6">
          <div className={`bg-white dark:bg-dark rounded-[3rem] shadow-xl border border-slate-200 dark:border-slate-800 min-h-[650px] flex flex-col transition-all duration-300 ${isLoading ? 'opacity-60 grayscale-[0.5]' : ''}`}>
            <div className="p-10 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/30 dark:bg-slate-900/10">
              <div className="text-left">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight">Day {activeDay}</h2>
                <p className="text-slate-500 dark:text-slate-400 text-sm font-medium">Refine your itinerary block by block.</p>
              </div>
              <button onClick={() => generateAITrip(query)} className="flex items-center gap-2 px-5 py-2.5 bg-white dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl text-xs font-black uppercase tracking-widest text-slate-700 dark:text-slate-300 transition-all outline-none border border-slate-200 dark:border-slate-700">
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin text-amber-500" /> : <RefreshCcw className="w-4 h-4" />}
                Regenerate
              </button>
            </div>

            <div className="p-10 space-y-6 overflow-y-auto">
              {itinerary.length > 0 ? (
                itinerary.map(item => (
                  <div key={item.id} className="group relative bg-white dark:bg-slate-800/50 border border-slate-100 dark:border-slate-800 hover:border-amber-400 p-8 rounded-[2rem] flex items-center gap-8 transition-all hover:shadow-2xl">
                    <GripVertical className="w-6 h-6 text-slate-200 shrink-0 cursor-grab" />
                    <div className="w-24 shrink-0 flex flex-col items-center">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Arrival</span>
                      <span className="text-base font-black text-amber-600 dark:text-amber-500">{item.time}</span>
                    </div>
                    <div className="flex-1 text-left">
                      <h4 className="font-black text-slate-900 dark:text-white text-xl group-hover:text-amber-600 transition-colors tracking-tight">{item.title}</h4>
                      <div className="flex items-center gap-4 mt-2">
                        <span className="text-[10px] px-3 py-1.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-black uppercase tracking-wider">{item.category}</span>
                        <span className="text-[10px] text-slate-400 font-black flex items-center gap-1 uppercase tracking-wider"><Clock className="w-3.5 h-3.5" /> {item.duration}</span>
                      </div>
                    </div>
                    <button onClick={() => removeActivity(item.id)} className="p-4 text-slate-300 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-2xl opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 className="w-6 h-6" />
                    </button>
                  </div>
                ))
              ) : !isLoading && (
                <div className="flex flex-col items-center justify-center py-24 text-center opacity-30">
                  <Navigation className="w-16 h-16 mb-6 dark:text-white" />
                  <p className="font-black text-xl dark:text-white uppercase tracking-widest">Plan is Empty</p>
                </div>
              )}
              {itinerary.length > 0 && (
                <button onClick={addActivity} className="w-full py-8 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-[2.5rem] text-slate-400 font-black text-xs uppercase tracking-[0.3em] hover:border-amber-400 hover:text-amber-600 hover:bg-amber-50/20 transition-all flex items-center justify-center gap-3 outline-none">
                  <Plus className="w-5 h-5" /> Add New Stop
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PlannerPage;

