  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [profileMenuOpen, setProfileMenuOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setProfileMenuOpen(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const navLinks: { name: string; view: ViewType }[] = [
    { name: 'How it Works', view: 'how-it-works' },
    { name: 'Features', view: 'features' },
    { name: 'Blog', view: 'blog' },
  ];

  const handleAction = (view: ViewType) => {
    navigateTo(view);
    setMobileMenuOpen(false);
    setProfileMenuOpen(false);
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      isScrolled 
        ? 'glass-morphism py-3 shadow-[0_10px_30px_rgba(0,0,0,0.03)]' 
        : 'bg-transparent py-5'
    }`}>
      <div className="container mx-auto px-4 md:px-6">
        <div className="flex items-center justify-between">
          <button 
            onClick={() => handleAction('home')} 
            className="flex items-center gap-2 cursor-pointer group outline-none"
          >
            <div className="bg-brand-dark dark:bg-brand-yellow p-2 rounded-xl group-hover:rotate-12 transition-transform shadow-lg">
              <Sparkles className="text-brand-yellow dark:text-brand-dark w-5 h-5 fill-current" />
            </div>
            <span className="text-2xl font-black tracking-tight text-brand-dark dark:text-white">
              YourTripy
            </span>
          </button>

          <div className="hidden md:flex items-center gap-10">
            {navLinks.map((link) => (
              <button 
                key={link.name}
                onClick={() => handleAction(link.view)}
                className={`text-sm font-black uppercase tracking-widest transition-colors outline-none ${
                  currentView === link.view 
                    ? 'text-sky-600 dark:text-brand-yellow border-b-2 border-current pb-1' 
                    : 'text-slate-500 hover:text-brand-dark dark:hover:text-white'
                }`}
              >
                {link.name}
              </button>
            ))}
          </div>

          <div className="hidden md:flex items-center gap-4">
            <button 
              onClick={toggleTheme}
              className="p-2.5 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-all"
            >
              {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>

            <div className="w-px h-6 bg-slate-200 dark:bg-slate-800 mx-2" />

            {user ? (
              <div className="relative" ref={profileRef}>
                <button 
                  onClick={() => setProfileMenuOpen(!profileMenuOpen)}
                  className="flex items-center gap-3 p-1.5 pl-4 pr-1 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-all border border-transparent hover:border-sky-500/30"
                >
                  <span className="text-sm font-black text-slate-700 dark:text-slate-300">{user.name.split(' ')[0]}</span>
                  {user.avatar ? (
                    <img src={user.avatar} className="w-8 h-8 rounded-full object-cover shadow-sm" alt="Profile" />
                  ) : (
                    <div className="w-8 h-8 bg-brand-yellow rounded-full flex items-center justify-center text-dark font-black text-xs">
                      {user.name[0]}
                    </div>
                  )}
                </button>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => handleAction('login')} 
                  className="px-5 py-2.5 text-sm font-bold text-slate-700 dark:text-slate-300 hover:text-sky-600 transition-colors"
                >
                  Log In
                </button>
                <button 
                  onClick={() => handleAction('signup')}
                  className="px-6 py-3 bg-brand-dark dark:bg-white text-white dark:text-brand-dark text-sm font-black rounded-2xl shadow-xl hover:scale-105 transition-all active:scale-95"
                >
                  Get Started
                </button>
              </div>
            )}
          </div>

          <div className="md:hidden">
            <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2 text-brand-dark dark:text-white">
              {mobileMenuOpen ? <X /> : <Menu />}
            </button>
          </div>
        </div>
      </div>

      {mobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 right-0 glass-morphism border-t border-slate-100 dark:border-slate-800 p-8 flex flex-col gap-6 shadow-2xl animate-in slide-in-from-top-4">
          {navLinks.map((link) => (
            <button key={link.name} onClick={() => handleAction(link.view)} className="text-xl font-black text-left text-brand-dark dark:text-white">{link.name}</button>
          ))}
          <div className="h-px bg-slate-100 dark:bg-slate-800 my-2" />
          <button onClick={() => handleAction('login')} className="w-full py-4 text-center font-black text-brand-dark dark:text-white rounded-2xl border border-slate-200 dark:border-slate-800">Log In</button>
          <button onClick={() => handleAction('signup')} className="w-full py-4 text-center font-black text-white bg-brand-dark rounded-2xl">Get Started</button>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

