import React, { useState, useEffect } from 'react';
import { 
  GripVertical, Plus, Trash2, MapPin, Navigation, 
  Calendar, Loader2, 
  Sparkles, RefreshCcw, Send, ArrowLeft, Clock
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { ViewType } from '../App';

interface Activity {
  id: string;
  time: string;
  title: string;
  category: string;
  duration: string;
}

interface PlannerPageProps {
  initialQuery?: string;
  navigateTo: (view: ViewType) => void;
}

const PlannerPage: React.FC<PlannerPageProps> = ({ initialQuery, navigateTo }) => {
  const [activeDay, setActiveDay] = useState(1);
  const [itinerary, setItinerary] = useState<Activity[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [query, setQuery] = useState(initialQuery || '');
  const [destinationName, setDestinationName] = useState(initialQuery || 'New Trip');

  useEffect(() => {
    if (initialQuery) {
      generateAITrip(initialQuery);
    }
  }, []);

  const generateAITrip = async (prompt: string) => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a one-day travel itinerary for: ${prompt}. Return exactly 4 activities in a logical time sequence. JSON format only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                title: { type: Type.STRING },
                category: { type: Type.STRING },
                duration: { type: Type.STRING }
              },
              required: ["time", "title", "category", "duration"]
            }
          }
        },
      });

      const data = JSON.parse(response.text || '[]');
      setItinerary(data.map((item: any) => ({ ...item, id: Math.random().toString(36).substr(2, 9) })));
      setDestinationName(prompt.split('in').pop()?.trim() || prompt.split(' ').slice(0, 2).join(' '));
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("AI Co-pilot encountered an error. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const removeActivity = (id: string) => setItinerary(prev => prev.filter(item => item.id !== id));
  const addActivity = () => {
    setItinerary([...itinerary, { id: Math.random().toString(36).substr(2, 9), time: "08:00 PM", title: "Custom Stop", category: "Custom", duration: "1h" }]);
  };

  return (
    <div className="pt-24 min-h-screen bg-slate-50 dark:bg-brand-dark/95 flex flex-col">
      <div className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-16 z-30 px-6 py-5 flex flex-col md:flex-row md:items-center justify-between gap-6 shadow-sm">
        <div className="flex items-center gap-5">
          <button onClick={() => navigateTo('home')} className="p-2.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors outline-none">
            <ArrowLeft className="w-5 h-5 text-slate-500" />
          </button>
          <div className="text-left">
            <h1 className="text-2xl font-black text-slate-900 dark:text-white flex items-center gap-3 capitalize tracking-tight">
              <MapPin className="w-6 h-6 text-sky-600 dark:text-brand-yellow" />
              {destinationName}
            </h1>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] ml-1">Live AI Workspace</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative group flex-grow md:w-96">
            <input 
              type="text" 
              placeholder="Refine your trip (e.g. 'Add coffee stops')..."
              className="w-full pl-6 pr-14 py-4 bg-slate-100 dark:bg-slate-800 border-2 border-transparent focus:bg-white dark:focus:bg-slate-900 focus:border-sky-500 rounded-2xl text-sm transition-all outline-none text-slate-900 dark:text-white font-bold"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && generateAITrip(query)}
            />
            <button onClick={() => generateAITrip(query)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-sky-600 outline-none transition-colors p-1">
              <Send className="w-5 h-5" />
            </button>
          </div>
          <button onClick={() => alert("Trip saved!")} className="px-8 py-4 bg-brand-dark dark:bg-brand-yellow text-white dark:text-brand-dark text-sm font-black rounded-2xl shadow-xl hover:scale-105 transition-all outline-none">Save Plan</button>
        </div>
      </div>

      <div className="flex-grow flex flex-col lg:flex-row container mx-auto px-4 py-12 gap-10 max-w-7xl">
        <aside className="lg:w-1/4 space-y-8">
          <div className="bg-white dark:bg-slate-900 p-10 rounded-[3rem] border border-slate-100 dark:border-slate-800 shadow-sm">
            <h4 className="font-black text-slate-400 uppercase text-[10px] tracking-[0.3em] mb-10 flex items-center justify-between">Timeline <Calendar className="w-4 h-4" /></h4>
            <div className="space-y-4">
              {[1, 2, 3].map(day => (
                <button 
                  key={day} 
                  onClick={() => setActiveDay(day)}
                  className={`w-full text-left px-6 py-5 rounded-[1.5rem] text-sm font-black transition-all flex items-center justify-between outline-none ${
                    activeDay === day ? 'bg-sky-600 dark:bg-brand-yellow text-white dark:text-brand-dark shadow-xl shadow-sky-500/10' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
                  }`}
                >
                  Day {day}
                </button>
              ))}
            </div>
          </div>
          <div className="bg-brand-dark dark:bg-slate-900 rounded-[3rem] p-10 text-white border border-slate-800 shadow-2xl relative overflow-hidden group">
            <div className="absolute -top-10 -right-10 w-40 h-40 bg-sky-500/10 blur-3xl rounded-full group-hover:scale-150 transition-transform duration-1000"></div>
            <h4 className="font-black flex items-center gap-3 mb-8 uppercase text-[10px] tracking-[0.3em] text-brand-yellow">AI Assistant</h4>
            <div className="space-y-4 relative z-10">
              <button onClick={() => generateAITrip(`Refine for ${query}: budget friendly options`)} className="w-full py-4 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Budget Mode</button>
              <button onClick={() => generateAITrip(`Refine for ${query}: add nature focus`)} className="w-full py-4 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Nature Mode</button>
            </div>
          </div>
        </aside>

        <div className="lg:w-3/4 space-y-8">
          <div className={`bg-white dark:bg-slate-900 rounded-[4rem] shadow-2xl border border-slate-100 dark:border-slate-800 min-h-[700px] flex flex-col transition-all duration-500 ${isLoading ? 'opacity-60 grayscale-[0.5]' : ''}`}>
            <div className="p-12 border-b border-slate-50 dark:border-slate-800 flex items-center justify-between bg-slate-50/20 dark:bg-slate-900/40">
              <div className="text-left">
                <h2 className="text-4xl font-black text-slate-900 dark:text-white tracking-tight">Day {activeDay}</h2>
                <p className="text-slate-400 text-sm font-bold mt-1">Refine each block for your perfect day.</p>
              </div>
              <button onClick={() => generateAITrip(query)} className="flex items-center gap-3 px-6 py-3.5 bg-white dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-700 dark:text-slate-300 transition-all border border-slate-200 dark:border-slate-700">
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin text-sky-600" /> : <RefreshCcw className="w-4 h-4" />}
                Full Refresh
              </button>
            </div>

            <div className="p-12 space-y-8">
              {itinerary.length > 0 ? (
                itinerary.map(item => (
                  <div key={item.id} className="group relative bg-white dark:bg-slate-800/40 border border-slate-100 dark:border-slate-800 hover:border-sky-400 p-10 rounded-[2.5rem] flex items-center gap-10 transition-all hover:shadow-2xl">
                    <GripVertical className="w-6 h-6 text-slate-200 shrink-0 cursor-grab" />
                    <div className="w-28 shrink-0 flex flex-col items-center">
                      <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-3">Time</span>
                      <span className="text-lg font-black text-sky-600 dark:text-brand-yellow">{item.time}</span>
                    </div>
                    <div className="flex-1 text-left">
                      <h4 className="font-black text-slate-900 dark:text-white text-2xl group-hover:text-sky-600 transition-colors tracking-tight leading-none mb-4">{item.title}</h4>
                      <div className="flex items-center gap-6">
                        <span className="text-[10px] px-3.5 py-2 rounded-xl bg-slate-50 dark:bg-slate-700 text-slate-500 dark:text-slate-400 font-black uppercase tracking-widest">{item.category}</span>
                        <span className="text-[10px] text-slate-400 font-black flex items-center gap-2 uppercase tracking-widest"><Clock className="w-4 h-4" /> {item.duration}</span>
                      </div>
                    </div>
                    <button onClick={() => removeActivity(item.id)} className="p-5 text-slate-200 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-3xl opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 className="w-7 h-7" />
                    </button>
                  </div>
                ))
              ) : !isLoading && (
                <div className="flex flex-col items-center justify-center py-32 text-center opacity-20">
                  <Navigation className="w-24 h-24 mb-8 dark:text-white" />
                  <p className="font-black text-2xl dark:text-white uppercase tracking-[0.3em]">No Activities Yet</p>
                </div>
              )}
              {itinerary.length > 0 && (
                <button onClick={addActivity} className="w-full py-10 border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-[3rem] text-slate-300 dark:text-slate-600 font-black text-[10px] uppercase tracking-[0.4em] hover:border-sky-400 hover:text-sky-600 hover:bg-sky-50/10 transition-all flex items-center justify-center gap-4 outline-none">
                  <Plus className="w-6 h-6" /> Add New stop
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PlannerPage;

