import React, { useState, useEffect } from 'react';
import LandingPage from './LandingPage';
import HowItWorksPage from './pages/HowItWorksPage';
import FeaturesPage from './pages/FeaturesPage';
import BlogPage from './pages/BlogPage';
import GuidebooksPage from './pages/GuidebooksPage';
import CommunityPage from './pages/CommunityPage';
import SupportPage from './pages/SupportPage';
import AboutPage from './pages/AboutPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfServicePage from './pages/TermsOfServicePage';
import ContactPage from './pages/ContactPage';
import PlannerPage from './pages/PlannerPage';
import LoginPage from './pages/LoginPage';
import SignUpPage from './pages/SignUpPage';
import Navbar from './components/Navbar';
import Footer from './components/Footer';

export type ViewType = 'home' | 'how-it-works' | 'features' | 'blog' | 'guidebooks' | 'community' | 'support' | 'about' | 'privacy' | 'terms' | 'contact' | 'planner' | 'login' | 'signup';

export interface User {
  name: string;
  email: string;
  avatar?: string;
}

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('home');
  const [searchQuery, setSearchQuery] = useState('');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    // Standardize to Light Mode
    document.documentElement.classList.remove('dark');

    // Mock session check
    const savedUser = localStorage.getItem('tripy_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const navigateTo = (newView: ViewType, query: string = '') => {
    setSearchQuery(query);
    setView(newView);
    window.scrollTo(0, 0);
  };

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('tripy_user', JSON.stringify(userData));
    navigateTo('home');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('tripy_user');
    navigateTo('home');
  };

  const renderView = () => {
    switch (view) {
      case 'planner': return <PlannerPage initialQuery={searchQuery} navigateTo={navigateTo} />;
      case 'how-it-works': return <HowItWorksPage />;
      case 'features': return <FeaturesPage />;
      case 'blog': return <BlogPage />;
      case 'guidebooks': return <GuidebooksPage />;
      case 'community': return <CommunityPage />;
      case 'support': return <SupportPage />;
      case 'about': return <AboutPage />;
      case 'privacy': return <PrivacyPolicyPage />;
      case 'terms': return <TermsOfServicePage />;
      case 'contact': return <ContactPage navigateTo={navigateTo} />;
      case 'login': return <LoginPage navigateTo={navigateTo} onLogin={handleLogin} />;
      case 'signup': return <SignUpPage navigateTo={navigateTo} onLogin={handleLogin} />;
      case 'home':
      default:
        return <LandingPage navigateTo={navigateTo} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-white transition-colors duration-300">
      <Navbar 
        navigateTo={navigateTo} 
        currentView={view} 
        user={user} 
        onLogout={handleLogout} 
      />
      <main className="flex-grow">
        {renderView()}
      </main>
      <Footer navigateTo={navigateTo} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Menu, X, Sparkles, User as UserIcon, LogOut, Settings, Map } from 'lucide-react';
import { ViewType, User } from '../App';

interface NavbarProps {
  navigateTo: (view: ViewType) => void;
  currentView: ViewType;
  user: User | null;
  onLogout: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ navigateTo, currentView, user, onLogout }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [profileMenuOpen, setProfileMenuOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setProfileMenuOpen(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const navLinks: { name: string; view: ViewType }[] = [
    { name: 'How it Works', view: 'how-it-works' },
    { name: 'Features', view: 'features' },
    { name: 'Blog', view: 'blog' },
  ];

  const handleAction = (view: ViewType) => {
    navigateTo(view);
    setMobileMenuOpen(false);
    setProfileMenuOpen(false);
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      isScrolled 
        ? 'glass-morphism py-3 shadow-[0_10px_30px_rgba(15,23,42,0.04)]' 
        : 'bg-transparent py-5'
    }`}>
      <div className="container mx-auto px-4 md:px-6">
        <div className="flex items-center justify-between">
          <button 
            onClick={() => handleAction('home')} 
            className="flex items-center gap-3 cursor-pointer group outline-none"
          >
            <div className="bg-brand-dark p-2.5 rounded-xl group-hover:rotate-12 transition-transform shadow-lg">
              <Sparkles className="text-brand-yellow w-5 h-5 fill-current" />
            </div>
            <span className="text-2xl font-black tracking-tight text-brand-dark">
              YourTripy
            </span>
          </button>

          <div className="hidden md:flex items-center gap-10">
            {navLinks.map((link) => (
              <button 
                key={link.name}
                onClick={() => handleAction(link.view)}
                className={`text-[13px] font-black uppercase tracking-[0.15em] transition-all outline-none ${
                  currentView === link.view 
                    ? 'text-brand-blue border-b-2 border-brand-blue pb-0.5' 
                    : 'text-brand-slate hover:text-brand-dark'
                }`}
              >
                {link.name}
              </button>
            ))}
          </div>

          <div className="hidden md:flex items-center gap-6">
            {user ? (
              <div className="relative" ref={profileRef}>
                <button 
                  onClick={() => setProfileMenuOpen(!profileMenuOpen)}
                  className="flex items-center gap-3 p-1.5 pl-4 pr-1 bg-brand-blue-soft hover:bg-brand-blue-light rounded-full transition-all border border-brand-blue/10"
                >
                  <span className="text-sm font-black text-brand-dark">{user.name.split(' ')[0]}</span>
                  {user.avatar ? (
                    <img src={user.avatar} className="w-8 h-8 rounded-full object-cover shadow-sm" alt="Profile" />
                  ) : (
                    <div className="w-8 h-8 bg-brand-yellow rounded-full flex items-center justify-center text-brand-dark font-black text-xs">
                      {user.name[0]}
                    </div>
                  )}
                </button>

                {profileMenuOpen && (
                  <div className="absolute right-0 mt-3 w-56 glass-morphism rounded-2xl shadow-2xl py-2 overflow-hidden animate-in fade-in zoom-in-95 duration-200 border border-brand-blue/10">
                    <div className="px-4 py-3 border-b border-slate-100">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Account</p>
                      <p className="text-sm font-bold text-brand-dark truncate">{user.email}</p>
                    </div>
                    <button onClick={() => handleAction('planner')} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-bold text-slate-600 hover:bg-brand-blue-soft hover:text-brand-blue transition-colors">
                      <Map className="w-4 h-4" /> My Workspace
                    </button>
                    <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-bold text-red-500 hover:bg-red-50 transition-colors">
                      <LogOut className="w-4 h-4" /> Sign Out
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => handleAction('login')} 
                  className="px-5 py-2.5 text-sm font-black uppercase tracking-widest text-brand-slate hover:text-brand-dark transition-colors"
                >
                  Login
                </button>
                <button 
                  onClick={() => handleAction('signup')}
                  className="px-7 py-3.5 bg-brand-dark text-white text-[13px] font-black uppercase tracking-widest rounded-2xl shadow-xl hover:scale-105 hover:bg-brand-blue transition-all active:scale-95"
                >
                  Join Now
                </button>
              </div>
            )}
          </div>

          <div className="md:hidden">
            <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2 text-brand-dark">
              {mobileMenuOpen ? <X /> : <Menu />}
            </button>
          </div>
        </div>
      </div>

      {mobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 right-0 glass-morphism p-8 flex flex-col gap-6 shadow-2xl animate-in slide-in-from-top-4">
          {navLinks.map((link) => (
            <button key={link.name} onClick={() => handleAction(link.view)} className="text-xl font-black text-left text-brand-dark">{link.name}</button>
          ))}
          <div className="h-px bg-slate-100 my-2" />
          <button onClick={() => handleAction('login')} className="w-full py-4 text-center font-black text-brand-dark rounded-2xl border border-brand-yellow">Log In</button>
          <button onClick={() => handleAction('signup')} className="w-full py-4 text-center font-black text-white bg-brand-dark rounded-2xl">Get Started</button>
        </div>
      )}
    </nav>
  );
};

