const PlannerPage: React.FC<PlannerPageProps> = ({ initialQuery, navigateTo }) => {
  const [activeDay, setActiveDay] = useState(1);
  const [itinerary, setItinerary] = useState<Activity[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [query, setQuery] = useState(initialQuery || '');
  const [destinationName, setDestinationName] = useState(initialQuery || 'New Trip');

  useEffect(() => {
    if (initialQuery) {
      generateAITrip(initialQuery);
    }
  }, []);

  const generateAITrip = async (prompt: string) => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a one-day travel itinerary for: ${prompt}. Return exactly 4 activities in a logical time sequence. JSON format only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                title: { type: Type.STRING },
                category: { type: Type.STRING },
                duration: { type: Type.STRING }
              },
              required: ["time", "title", "category", "duration"]
            }
          }
        },
      });

      const data = JSON.parse(response.text || '[]');
      setItinerary(data.map((item: any) => ({ ...item, id: Math.random().toString(36).substr(2, 9) })));
      setDestinationName(prompt.split('in').pop()?.trim() || prompt.split(' ').slice(0, 2).join(' '));
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("AI Co-pilot encountered an error. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const removeActivity = (id: string) => setItinerary(prev => prev.filter(item => item.id !== id));
  const addActivity = () => {
    setItinerary([...itinerary, { id: Math.random().toString(36).substr(2, 9), time: "08:00 PM", title: "Custom Stop", category: "Custom", duration: "1h" }]);
  };

  return (
    <div className="pt-24 min-h-screen bg-brand-blue-soft/50 flex flex-col">
      <div className="bg-white border-b border-brand-blue-soft sticky top-16 z-30 px-8 py-6 flex flex-col md:flex-row md:items-center justify-between gap-8 shadow-sm">
        <div className="flex items-center gap-6">
          <button onClick={() => navigateTo('home')} className="p-3 hover:bg-brand-blue-soft rounded-2xl transition-all outline-none">
            <ArrowLeft className="w-6 h-6 text-brand-slate" />
          </button>
          <div className="text-left">
            <h1 className="text-3xl font-black text-brand-dark flex items-center gap-3 capitalize tracking-tight">
              <MapPin className="w-8 h-8 text-brand-blue" />
              {destinationName}
            </h1>
            <p className="text-[11px] text-brand-blue font-black uppercase tracking-[0.25em] ml-1">Drafting Engine v2.0</p>
          </div>
        </div>

        <div className="flex items-center gap-5">
          <div className="relative group flex-grow md:w-[500px]">
            <input 
              type="text" 
              placeholder="Refine co-pilot logic (e.g. 'More rooftop bars')..."
              className="w-full pl-7 pr-16 py-5 bg-brand-blue-soft border-2 border-transparent focus:bg-white focus:border-brand-blue rounded-3xl text-sm transition-all outline-none text-brand-dark font-bold placeholder:text-slate-300"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && generateAITrip(query)}
            />
            <button onClick={() => generateAITrip(query)} className="absolute right-5 top-1/2 -translate-y-1/2 text-brand-slate hover:text-brand-blue outline-none transition-colors p-1.5">
              <Send className="w-6 h-6" />
            </button>
          </div>
          <button onClick={() => alert("Trip saved!")} className="px-10 py-5 bg-brand-dark text-white text-[13px] font-black uppercase tracking-widest rounded-3xl shadow-xl hover:bg-brand-blue transition-all outline-none">Finalize Plan</button>
        </div>
      </div>

      <div className="flex-grow flex flex-col lg:flex-row container mx-auto px-6 py-16 gap-12 max-w-[1400px]">
        <aside className="lg:w-[320px] space-y-10">
          <div className="bg-white p-12 rounded-[3.5rem] border border-brand-blue/10 shadow-sm">
            <h4 className="font-black text-slate-300 uppercase text-[11px] tracking-[0.4em] mb-12 flex items-center justify-between">Timeline <Calendar className="w-4 h-4 opacity-30" /></h4>
            <div className="space-y-5">
              {[1, 2, 3].map(day => (
                <button 
                  key={day} 
                  onClick={() => setActiveDay(day)}
                  className={`w-full text-left px-7 py-6 rounded-[2rem] text-sm font-black transition-all flex items-center justify-between outline-none ${
                    activeDay === day ? 'bg-brand-blue text-white shadow-2xl shadow-brand-blue/30 scale-[1.05]' : 'text-brand-slate hover:bg-brand-blue-soft'
                  }`}
                >
                  Day {day}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-brand-dark rounded-[3.5rem] p-12 text-white shadow-[0_40px_80px_-20px_rgba(15,23,42,0.4)] relative overflow-hidden group">
            <div className="absolute -top-12 -right-12 w-48 h-48 bg-brand-blue/20 blur-3xl rounded-full group-hover:scale-125 transition-transform duration-1000"></div>
            <h4 className="font-black flex items-center gap-3 mb-10 uppercase text-[11px] tracking-[0.4em] text-brand-yellow">Smart Refiner</h4>
            <div className="space-y-5 relative z-10">
              <button onClick={() => generateAITrip(`Refine for ${query}: optimized for minimal walking`)} className="w-full py-5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all">Lazy Explorer</button>
              <button onClick={() => generateAITrip(`Refine for ${query}: add only high-rated spots`)} className="w-full py-5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all">Prestige Only</button>
            </div>
          </div>
        </aside>

        <div className="flex-1 space-y-10">
          <div className={`bg-white rounded-[4.5rem] shadow-2xl border border-brand-blue-soft min-h-[800px] flex flex-col transition-all duration-700 ${isLoading ? 'opacity-50 blur-sm pointer-events-none' : ''}`}>
            <div className="px-16 py-14 border-b border-brand-blue-soft flex items-center justify-between bg-brand-blue-soft/20">
              <div className="text-left">
                <h2 className="text-5xl font-black text-brand-dark tracking-tighter">Day {activeDay}</h2>
                <p className="text-brand-slate text-sm font-bold mt-2">Adjust each time block to perfection.</p>
              </div>
              <button onClick={() => generateAITrip(query)} className="flex items-center gap-3 px-8 py-4 bg-white hover:bg-brand-blue-soft rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-brand-dark transition-all border border-brand-blue-soft">
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin text-brand-blue" /> : <RefreshCcw className="w-4 h-4" />}
                Full Regeneration
              </button>
            </div>

            <div className="px-16 py-16 space-y-10">
              {itinerary.length > 0 ? (
                itinerary.map(item => (
                  <div key={item.id} className="group relative bg-white border border-brand-blue-soft hover:border-brand-blue p-12 rounded-[3.5rem] flex items-center gap-12 transition-all hover:shadow-[0_40px_80px_-20px_rgba(15,23,42,0.1)]">
                    <GripVertical className="w-7 h-7 text-slate-200 shrink-0 cursor-grab group-hover:text-brand-blue/30 transition-colors" />
                    <div className="w-32 shrink-0 flex flex-col items-center border-r border-brand-blue-soft">
                      <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em] mb-3">Est. Arrival</span>
                      <span className="text-xl font-black text-brand-blue">{item.time}</span>
                    </div>
                    <div className="flex-1 text-left">
                      <h4 className="font-black text-brand-dark text-3xl group-hover:text-brand-blue transition-colors tracking-tight mb-5 leading-none">{item.title}</h4>
                      <div className="flex items-center gap-8">
                        <span className="text-[11px] px-4 py-2 rounded-xl bg-brand-blue-soft text-brand-blue font-black uppercase tracking-widest">{item.category}</span>
                        <span className="text-[11px] text-brand-slate font-black flex items-center gap-2.5 uppercase tracking-widest"><Clock className="w-4 h-4 text-brand-blue" /> {item.duration}</span>
                      </div>
                    </div>
                    <button onClick={() => removeActivity(item.id)} className="p-6 text-slate-200 hover:text-red-500 hover:bg-red-50 rounded-3xl opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 className="w-8 h-8" />
                    </button>
                  </div>
                ))
              ) : !isLoading && (
                <div className="flex flex-col items-center justify-center py-40 text-center opacity-10">
                  <Navigation className="w-32 h-32 mb-10 text-brand-dark" />
                  <p className="font-black text-3xl text-brand-dark uppercase tracking-[0.5em]">Canvas empty</p>
                </div>
              )}
              {itinerary.length > 0 && (
                <button onClick={addActivity} className="w-full py-12 border-2 border-dashed border-brand-blue/10 rounded-[3.5rem] text-slate-300 font-black text-[12px] uppercase tracking-[0.5em] hover:border-brand-blue hover:text-brand-blue hover:bg-brand-blue-soft/30 transition-all flex items-center justify-center gap-5 outline-none">
                  <Plus className="w-7 h-7" /> Add custom block
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PlannerPage;

