import React, { useState, useEffect, useRef } from 'react';
import { Menu, X, Sparkles, User as UserIcon, LogOut, Settings, Map } from 'lucide-react';
import { ViewType, User } from '../App';

interface NavbarProps {
  navigateTo: (view: ViewType) => void;
  currentView: ViewType;
  user: User | null;
  onLogout: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ navigateTo, currentView, user, onLogout }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [profileMenuOpen, setProfileMenuOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setProfileMenuOpen(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const navLinks: { name: string; view: ViewType }[] = [
    { name: 'How it Works', view: 'how-it-works' },
    { name: 'Features', view: 'features' },
    { name: 'Blog', view: 'blog' },
  ];

  const handleAction = (view: ViewType) => {
    navigateTo(view);
    setMobileMenuOpen(false);
    setProfileMenuOpen(false);
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      isScrolled 
        ? 'glass-morphism py-3 shadow-[0_10px_40px_rgba(255,107,0,0.05)]' 
        : 'bg-transparent py-5'
    }`}>
      <div className="container mx-auto px-4 md:px-6">
        <div className="flex items-center justify-between">
          <button 
            onClick={() => handleAction('home')} 
            className="flex items-center gap-3 cursor-pointer group outline-none"
          >
            <div className="bg-brand-orange p-2.5 rounded-xl group-hover:rotate-12 transition-transform shadow-lg shadow-brand-orange/20">
              <Sparkles className="text-white w-5 h-5 fill-current" />
            </div>
            <span className="text-2xl font-black tracking-tight text-brand-dark">
              YourTripy
            </span>
          </button>

          <div className="hidden md:flex items-center gap-10">
            {navLinks.map((link) => (
              <button 
                key={link.name}
                onClick={() => handleAction(link.view)}
                className={`text-[13px] font-black uppercase tracking-[0.15em] transition-all outline-none ${
                  currentView === link.view 
                    ? 'text-brand-orange border-b-2 border-brand-orange pb-0.5' 
                    : 'text-brand-slate hover:text-brand-orange'
                }`}
              >
                {link.name}
              </button>
            ))}
          </div>

          <div className="hidden md:flex items-center gap-6">
            {user ? (
              <div className="relative" ref={profileRef}>
                <button 
                  onClick={() => setProfileMenuOpen(!profileMenuOpen)}
                  className="flex items-center gap-3 p-1.5 pl-4 pr-1 bg-brand-orange-soft hover:bg-brand-orange/10 rounded-full transition-all border border-brand-orange/10"
                >
                  <span className="text-sm font-black text-brand-dark">{user.name.split(' ')[0]}</span>
                  {user.avatar ? (
                    <img src={user.avatar} className="w-8 h-8 rounded-full object-cover shadow-sm" alt="Profile" />
                  ) : (
                    <div className="w-8 h-8 bg-brand-orange rounded-full flex items-center justify-center text-white font-black text-xs">
                      {user.name[0]}
                    </div>
                  )}
                </button>

                {profileMenuOpen && (
                  <div className="absolute right-0 mt-3 w-56 glass-morphism rounded-3xl shadow-2xl py-3 overflow-hidden animate-in fade-in zoom-in-95 duration-200 border border-brand-orange/5">
                    <button onClick={() => handleAction('planner')} className="w-full flex items-center gap-3 px-5 py-3 text-sm font-bold text-slate-600 hover:bg-brand-orange-soft hover:text-brand-orange transition-colors">
                      <Map className="w-4 h-4" /> Trip Canvas
                    </button>
                    <button onClick={onLogout} className="w-full flex items-center gap-3 px-5 py-3 text-sm font-bold text-red-500 hover:bg-red-50 transition-colors border-t border-slate-50">
                      <LogOut className="w-4 h-4" /> Sign Out
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => handleAction('login')} 
                  className="px-5 py-2.5 text-sm font-black uppercase tracking-widest text-brand-slate hover:text-brand-orange transition-colors"
                >
                  Login
