import React, { useState, useEffect } from 'react';
import { 
  GripVertical, Plus, Trash2, MapPin, Navigation, 
  Calendar, Loader2, 
  Sparkles, RefreshCcw, Send, ArrowLeft, Clock
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { ViewType } from '../App';

interface Activity {
  id: string;
  time: string;
  title: string;
  category: string;
  duration: string;
}

interface PlannerPageProps {
  initialQuery?: string;
  navigateTo: (view: ViewType) => void;
}

const PlannerPage: React.FC<PlannerPageProps> = ({ initialQuery, navigateTo }) => {
  const [activeDay, setActiveDay] = useState(1);
  const [itinerary, setItinerary] = useState<Activity[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [query, setQuery] = useState(initialQuery || '');
  const [destinationName, setDestinationName] = useState(initialQuery || 'New Trip');

  useEffect(() => {
    if (initialQuery) {
      generateAITrip(initialQuery);
    }
  }, []);

  const generateAITrip = async (prompt: string) => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a one-day travel itinerary for: ${prompt}. Return exactly 4 activities in a logical time sequence. JSON format only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                title: { type: Type.STRING },
                category: { type: Type.STRING },
                duration: { type: Type.STRING }
              },
              required: ["time", "title", "category", "duration"]
            }
          }
        },
      });

      const data = JSON.parse(response.text || '[]');
      setItinerary(data.map((item: any) => ({ ...item, id: Math.random().toString(36).substr(2, 9) })));
      setDestinationName(prompt.split('in').pop()?.trim() || prompt.split(' ').slice(0, 2).join(' '));
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("AI Co-pilot encountered an error.");
    } finally {
      setIsLoading(false);
    }
  };

  const removeActivity = (id: string) => setItinerary(prev => prev.filter(item => item.id !== id));
  const addActivity = () => {
    setItinerary([...itinerary, { id: Math.random().toString(36).substr(2, 9), time: "08:00 PM", title: "Custom Stop", category: "Custom", duration: "1h" }]);
  };

  return (
    <div className="pt-24 min-h-screen bg-brand-sky-light/50 flex flex-col">
      <div className="bg-white border-b border-brand-sky-light sticky top-16 z-30 px-8 py-6 flex flex-col md:flex-row md:items-center justify-between gap-8 shadow-sm">
        <div className="flex items-center gap-6">
          <button onClick={() => navigateTo('home')} className="p-3 hover:bg-brand-sky-light rounded-[1.5rem] transition-all outline-none">
            <ArrowLeft className="w-6 h-6 text-brand-slate" />
          </button>
          <div className="text-left">
            <h1 className="text-3xl font-black text-brand-dark flex items-center gap-3 capitalize tracking-tight">
              <MapPin className="w-8 h-8 text-brand-orange" />
              {destinationName}
            </h1>
            <p className="text-[11px] text-brand-orange font-black uppercase tracking-[0.25em] ml-1">AI Workspace v2.0</p>
          </div>
        </div>

        <div className="flex items-center gap-5">
          <div className="relative group flex-grow md:w-[500px]">
            <input 
              type="text" 
              placeholder="Refine co-pilot logic (e.g. 'Add street food')..."
              className="w-full pl-7 pr-16 py-5 bg-brand-sky-light border-2 border-transparent focus:bg-white focus:border-brand-orange rounded-[2rem] text-sm transition-all outline-none text-brand-dark font-bold placeholder:text-slate-300"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && generateAITrip(query)}
            />
            <button onClick={() => generateAITrip(query)} className="absolute right-5 top-1/2 -translate-y-1/2 text-brand-slate hover:text-brand-orange outline-none transition-colors p-1.5">
              <Send className="w-6 h-6" />
            </button>
          </div>
          <button onClick={() => alert("Trip saved!")} className="px-10 py-5 bg-brand-orange text-white text-[13px] font-black uppercase tracking-widest rounded-[2rem] shadow-xl hover:bg-brand-dark transition-all outline-none">Save Changes</button>
        </div>
      </div>

      <div className="flex-grow flex flex-col lg:flex-row container mx-auto px-6 py-16 gap-12 max-w-[1400px]">
        <aside className="lg:w-[320px] space-y-10">
          <div className="bg-white p-12 rounded-[4rem] border border-brand-sky-light shadow-sm">
            <h4 className="font-black text-slate-300 uppercase text-[11px] tracking-[0.4em] mb-12 flex items-center justify-between">Timeline <Calendar className="w-4 h-4 opacity-30" /></h4>
            <div className="space-y-5">
              {[1, 2, 3].map(day => (
                <button 
                  key={day} 
                  onClick={() => setActiveDay(day)}
                  className={`w-full text-left px-7 py-6 rounded-[2rem] text-sm font-black transition-all flex items-center justify-between outline-none ${
                    activeDay === day ? 'bg-brand-orange text-white shadow-2xl shadow-brand-orange/30 scale-[1.05]' : 'text-brand-slate hover:bg-brand-sky-light'
                  }`}
                >
                  Day {day}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-brand-dark rounded-[4rem] p-12 text-white shadow-[0_40px_80px_-20px_rgba(15,23,42,0.4)] relative overflow-hidden group">
            <div className="absolute -top-12 -right-12 w-48 h-48 bg-brand-orange/20 blur-3xl rounded-full group-hover:scale-125 transition-transform duration-1000"></div>
            <h4 className="font-black flex items-center gap-3 mb-10 uppercase text-[11px] tracking-[0.4em] text-brand-orange">Refinement Tools</h4>
            <div className="space-y-5 relative z-10">
              <button onClick={() => generateAITrip(`Refine for ${query}: minimal walking`)} className="w-full py-5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-[1.5rem] text-[10px] font-black uppercase tracking-[0.2em] transition-all">Avoid Walking</button>
              <button onClick={() => generateAITrip(`Refine for ${query}: photography spots`)} className="w-full py-5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-[1.5rem] text-[10px] font-black uppercase tracking-[0.2em] transition-all">Best for Photos</button>
            </div>
          </div>
        </aside>

        <div className="flex-1 space-y-10">
          <div className={`bg-white rounded-[5rem] shadow-2xl border border-brand-sky-light min-h-[800px] flex flex-col transition-all duration-700 ${isLoading ? 'opacity-50 blur-sm pointer-events-none' : ''}`}>
            <div className="px-16 py-14 border-b border-brand-sky-light flex items-center justify-between bg-brand-sky-light/30">
              <div className="text-left">
                <h2 className="text-5xl font-black text-brand-dark tracking-tighter">Day {activeDay}</h2>
                <p className="text-brand-slate text-sm font-bold mt-2">Personalize each time block for your journey.</p>
              </div>
              <button onClick={() => generateAITrip(query)} className="flex items-center gap-3 px-8 py-4 bg-white hover:bg-brand-sky-light rounded-[1.5rem] text-[11px] font-black uppercase tracking-[0.2em] text-brand-dark transition-all border border-brand-sky-light">
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin text-brand-orange" /> : <RefreshCcw className="w-4 h-4" />}
                Regenerate Day
              </button>
            </div>

            <div className="px-16 py-16 space-y-10">
              {itinerary.length > 0 ? (
                itinerary.map(item => (
                  <div key={item.id} className="group relative bg-white border border-brand-sky-light hover:border-brand-orange p-12 rounded-[4rem] flex items-center gap-12 transition-all hover:shadow-[0_40px_80px_-20px_rgba(255,107,0,0.06)]">
                    <GripVertical className="w-7 h-7 text-slate-200 shrink-0 cursor-grab group-hover:text-brand-orange/40 transition-colors" />
                    <div className="w-32 shrink-0 flex flex-col items-center border-r border-brand-sky-light">
                      <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em] mb-3">Time</span>
                      <span className="text-xl font-black text-brand-orange">{item.time}</span>
                    </div>
                    <div className="flex-1 text-left">
                      <h4 className="font-black text-brand-dark text-3xl group-hover:text-brand-orange transition-colors tracking-tight mb-5 leading-none">{item.title}</h4>
                      <div className="flex items-center gap-8">
                        <span className="text-[11px] px-4 py-2 rounded-xl bg-brand-sky-light text-brand-blue font-black uppercase tracking-widest">{item.category}</span>
                        <span className="text-[11px] text-brand-slate font-black flex items-center gap-2.5 uppercase tracking-widest"><Clock className="w-4 h-4 text-brand-orange" /> {item.duration}</span>
                      </div>
                    </div>
                    <button onClick={() => removeActivity(item.id)} className="p-6 text-slate-200 hover:text-red-500 hover:bg-red-50 rounded-[2rem] opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 className="w-8 h-8" />
                    </button>
                  </div>
                ))
              ) : !isLoading && (
                <div className="flex flex-col items-center justify-center py-40 text-center opacity-10">
                  <Navigation className="w-32 h-32 mb-10 text-brand-dark" />
                  <p className="font-black text-3xl text-brand-dark uppercase tracking-[0.5em]">Canvas empty</p>
                </div>
              )}
              {itinerary.length > 0 && (
                <button onClick={addActivity} className="w-full py-12 border-2 border-dashed border-brand-orange/10 rounded-[4rem] text-slate-300 font-black text-[12px] uppercase tracking-[0.5em] hover:border-brand-orange hover:text-brand-orange hover:bg-brand-orange-soft transition-all flex items-center justify-center gap-5 outline-none">
                  <Plus className="w-7 h-7" /> Add custom stop
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PlannerPage;

import React, { useState, useEffect } from 'react';
import LandingPage from './LandingPage';
import HowItWorksPage from './pages/HowItWorksPage';
import FeaturesPage from './pages/FeaturesPage';
import BlogPage from './pages/BlogPage';
import GuidebooksPage from './pages/GuidebooksPage';
import CommunityPage from './pages/CommunityPage';
import SupportPage from './pages/SupportPage';
import AboutPage from './pages/AboutPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfServicePage from './pages/TermsOfServicePage';
import ContactPage from './pages/ContactPage';
import PlannerPage from './pages/PlannerPage';
import LoginPage from './pages/LoginPage';
import SignUpPage from './pages/SignUpPage';
import Navbar from './components/Navbar';
import Footer from './components/Footer';

export type ViewType = 'home' | 'how-it-works' | 'features' | 'blog' | 'guidebooks' | 'community' | 'support' | 'about' | 'privacy' | 'terms' | 'contact' | 'planner' | 'login' | 'signup';

export interface User {
  name: string;
  email: string;
  avatar?: string;
}

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('home');
  const [searchQuery, setSearchQuery] = useState('');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    // Standardize to Midnight theme
    document.documentElement.classList.add('dark');

    // Mock session check
    const savedUser = localStorage.getItem('tripy_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const navigateTo = (newView: ViewType, query: string = '') => {
    setSearchQuery(query);
    setView(newView);
    window.scrollTo(0, 0);
  };

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('tripy_user', JSON.stringify(userData));
    navigateTo('home');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('tripy_user');
    navigateTo('home');
  };

  const renderView = () => {
    switch (view) {
      case 'planner': return <PlannerPage initialQuery={searchQuery} navigateTo={navigateTo} />;
      case 'how-it-works': return <HowItWorksPage />;
      case 'features': return <FeaturesPage />;
      case 'blog': return <BlogPage />;
      case 'guidebooks': return <GuidebooksPage />;
      case 'community': return <CommunityPage />;
      case 'support': return <SupportPage />;
      case 'about': return <AboutPage />;
      case 'privacy': return <PrivacyPolicyPage />;
      case 'terms': return <TermsOfServicePage />;
      case 'contact': return <ContactPage navigateTo={navigateTo} />;
      case 'login': return <LoginPage navigateTo={navigateTo} onLogin={handleLogin} />;
      case 'signup': return <SignUpPage navigateTo={navigateTo} onLogin={handleLogin} />;
      case 'home':
      default:
        return <LandingPage navigateTo={navigateTo} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-brand-deep text-white selection:bg-brand-primary selection:text-white">
      <Navbar 
        navigateTo={navigateTo} 
        currentView={view} 
        user={user} 
        onLogout={handleLogout} 
      />
      <main className="flex-grow">
        {renderView()}
      </main>
      <Footer navigateTo={navigateTo} />
    </div>
  );
};

export default App;

