import React, { useState, useEffect, useRef } from 'react';
import { Menu, X, Sparkles, User as UserIcon, LogOut, Settings, Map, Smartphone } from 'lucide-react';
import { ViewType, User } from '../App';

interface NavbarProps {
  navigateTo: (view: ViewType) => void;
  currentView: ViewType;
  user: User | null;
  onLogout: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ navigateTo, currentView, user, onLogout }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [profileMenuOpen, setProfileMenuOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setProfileMenuOpen(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const navLinks: { name: string; view: ViewType }[] = [
    { name: 'For Creators', view: 'community' },
    { name: 'For Business', view: 'about' },
    { name: 'Get inspired', view: 'blog' },
  ];

  const handleAction = (view: ViewType) => {
    navigateTo(view);
    setMobileMenuOpen(false);
    setProfileMenuOpen(false);
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      isScrolled 
        ? 'glass-morphism py-3 shadow-[0_5px_30px_rgba(0,0,0,0.05)]' 
        : 'bg-transparent py-6'
    }`}>
      <div className="container mx-auto px-4 md:px-8">
        <div className="flex items-center justify-between">
          <button 
            onClick={() => handleAction('home')} 
            className="flex items-center gap-2 cursor-pointer outline-none group"
          >
            <div className="p-1 rounded-lg group-hover:scale-110 transition-transform">
              <Sparkles className="text-brand-dark w-6 h-6 fill-current" />
            </div>
            <span className="text-2xl font-black tracking-tighter text-brand-dark">
              mindtrip.
            </span>
          </button>

          <div className="hidden md:flex items-center gap-12">
            {navLinks.map((link) => (
              <button 
                key={link.name}
                onClick={() => handleAction(link.view)}
                className={`text-[13px] font-bold transition-all outline-none ${
                  currentView === link.view 
                    ? 'text-brand-dark' 
                    : 'text-brand-dark/50 hover:text-brand-dark'
                }`}
              >
                <span className="italic mr-1 text-[11px] opacity-60">for</span> {link.name.replace('For ', '')}
              </button>
            ))}
          </div>

          <div className="hidden md:flex items-center gap-8">
            <button className="flex items-center gap-2 text-[13px] font-bold text-brand-dark hover:opacity-60 transition-all">
              <Smartphone className="w-4 h-4" /> Get app
            </button>

            {user ? (
              <div className="relative" ref={profileRef}>
                <button 
                  onClick={() => setProfileMenuOpen(!profileMenuOpen)}
                  className="flex items-center gap-2 p-1 pl-3 pr-1 bg-black/5 hover:bg-black/10 rounded-full transition-all"
                >
                  <span className="text-xs font-bold text-brand-dark">{user.name.split(' ')[0]}</span>
                  {user.avatar ? (
                    <img src={user.avatar} className="w-7 h-7 rounded-full object-cover shadow-sm" alt="Profile" />
                  ) : (
                    <div className="w-7 h-7 bg-brand-dark rounded-full flex items-center justify-center text-white font-bold text-[10px]">
                      {user.name[0]}
                    </div>
                  )}
                </button>

                {profileMenuOpen && (
                  <div className="absolute right-0 mt-3 w-56 glass-morphism rounded-2xl shadow-2xl py-2 overflow-hidden animate-in fade-in zoom-in-95 duration-200 border border-black/5">
                    <button onClick={() => handleAction('planner')} className="w-full flex items-center gap-3 px-5 py-3 text-sm font-bold text-brand-dark hover:bg-brand-primary transition-colors">
                      <Map className="w-4 h-4" /> Trip Hub
                    </button>
                    <button onClick={onLogout} className="w-full flex items-center gap-3 px-5 py-3 text-sm font-bold text-red-500 hover:bg-red-50 transition-colors border-t border-black/5">
                      <LogOut className="w-4 h-4" /> Sign Out
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => handleAction('login')} 
                  className="text-[13px] font-bold text-brand-dark hover:opacity-60 transition-colors"
                >
                  Log in
                </button>
                <button 
                  onClick={() => handleAction('signup')}
                  className="px-6 py-2.5 bg-brand-dark text-white text-[13px] font-bold rounded-full hover:scale-105 hover:bg-black transition-all active:scale-95"
                >
                  Get started
                </button>
              </div>
            )}
          </div>

          <div className="md:hidden flex items-center gap-4">
            <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2 text-brand-dark">
              {mobileMenuOpen ? <X /> : <Menu />}
            </button>
          </div>
        </div>
      </div>

      {mobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 right-0 glass-morphism p-8 flex flex-col gap-6 shadow-2xl animate-in slide-in-from-top-4">
          {navLinks.map((link) => (
            <button key={link.name} onClick={() => handleAction(link.view)} className="text-xl font-black text-left text-brand-dark">{link.name}</button>
          ))}
          <div className="h-px bg-black/5 my-2" />
          <button onClick={() => handleAction('login')} className="w-full py-4 text-center font-black text-brand-dark">Log In</button>
          <button onClick={() => handleAction('signup')} className="w-full py-4 text-center font-black text-white bg-brand-dark rounded-full">Get Started</button>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

